import{_ as r,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"PHP Web Scraping","description":"","frontmatter":{},"headers":[],"relativePath":"web-scraping/php-web-scraping.md","filePath":"web-scraping/php-web-scraping.md"}'),l={name:"web-scraping/php-web-scraping.md"};function o(n,e,s,h,u,b){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="php-web-scraping" tabindex="-1">PHP Web Scraping <a class="header-anchor" href="#php-web-scraping" aria-label="Permalink to &quot;PHP Web Scraping&quot;">​</a></h1><p>This list contains PHP libraries related to web scraping and data processing.</p><ul><li>PHP Web Scraping <ul><li>Network</li><li>Web-scraping Frameworks</li><li>HTML/XML Parsing</li><li>Text processing</li><li>Specific Formats Processing</li><li>Natural Language Processing</li><li>Browser automation and emulation</li><li>Multiprocessing</li><li>Queue</li><li>Cloud Computing</li><li>Email</li><li>URL Manipulation</li><li>Web Content Extracting</li><li>Asynchronous</li><li>WebSocket</li><li>DNS Resolving</li><li>Computer Vision</li><li>Geocoding</li><li>API Clients</li><li>Other PHP Lists</li></ul></li></ul><h2 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h2><ul><li><a href="https://github.com/guzzle/guzzle" target="_blank" rel="noreferrer">Guzzle</a> - A comprehensive HTTP client.</li><li><a href="https://github.com/kriswallsmith/Buzz" target="_blank" rel="noreferrer">Buzz</a> - Another HTTP client.</li><li><a href="https://github.com/rmccue/Requests" target="_blank" rel="noreferrer">Requests</a> - A simple HTTP library.</li><li><a href="https://github.com/nategood/httpful" target="_blank" rel="noreferrer">HTTPFul</a> - A chainable HTTP client.</li><li><a href="https://github.com/fabpot/Goutte" target="_blank" rel="noreferrer">Goutte</a> - A simple web scraper.</li><li><a href="https://github.com/mvdbos/php-spider" target="_blank" rel="noreferrer">PHP Spider</a> - A comprehensive web spider.</li></ul><h3 id="web-scraping-frameworks" tabindex="-1">Web-Scraping Frameworks <a class="header-anchor" href="#web-scraping-frameworks" aria-label="Permalink to &quot;Web-Scraping Frameworks&quot;">​</a></h3><ul><li><a href="https://github.com/crwlrsoft/crawler" target="_blank" rel="noreferrer">Crawler</a> - (crwlr) - Library for Rapid (Web) Crawler and Scraper Development</li><li><a href="https://github.com/roach-php/core" target="_blank" rel="noreferrer">Roach</a> - It is port of the popular Scrapy package for Python. Include adapter to Laravel and Symfony</li></ul><h3 id="html-xml-parsing" tabindex="-1">HTML/XML Parsing <a class="header-anchor" href="#html-xml-parsing" aria-label="Permalink to &quot;HTML/XML Parsing&quot;">​</a></h3><ul><li><a href="https://github.com/Masterminds/html5-php" target="_blank" rel="noreferrer">HTML5 PHP</a> - An HTML5 parser and serializer library.</li><li><a href="https://github.com/technosophos/querypath" target="_blank" rel="noreferrer">QueryPath</a> - a jQuery-like library for working with XML and HTML documents in PHP. It now contains support for HTML5 via the HTML5-PHP project.</li><li><a href="https://github.com/Imangazaliev/DiDOM" target="_blank" rel="noreferrer">DiDOM</a> - Super fast HTML parser (because it was built on top of plain PHP).</li><li><a href="https://github.com/spekulatius/phpscraper" target="_blank" rel="noreferrer">PHPScraper</a> - A highly opinionated web interface.</li><li><a href="https://github.com/symfony/dom-crawler" target="_blank" rel="noreferrer">DomCrawler</a> - (Symfony) - The DomCrawler component eases DOM navigation for HTML and XML documents.</li></ul><h3 id="text-processing" tabindex="-1">Text Processing <a class="header-anchor" href="#text-processing" aria-label="Permalink to &quot;Text Processing&quot;">​</a></h3><p><em>Libraries for parsing and manipulating plain texts.</em></p><ul><li>General <ul><li><a href="https://github.com/sensiolabs/ansi-to-html" target="_blank" rel="noreferrer">ANSI to HTML5</a> - An ANSI to HTML5 converter library.</li><li><a href="https://github.com/nicolas-grekas/Patchwork-UTF8" target="_blank" rel="noreferrer">Patchwork UTF-8</a> - A portable library for working with UTF-8 strings.</li><li><a href="https://github.com/hoaproject/Ustring" target="_blank" rel="noreferrer">Hoa String</a> - Another UTF-8 string library.</li><li><a href="https://github.com/danielstjules/Stringy" target="_blank" rel="noreferrer">Stringy</a> - A string manipulation library with multibyte support.</li><li><a href="https://github.com/mikeemoo/ColorJizz-PHP" target="_blank" rel="noreferrer">Color Jizz</a> - A library for manipulating and converting colours.</li><li><a href="https://github.com/kzykhys/Text" target="_blank" rel="noreferrer">Text</a> - A text manipulation library.</li><li><a href="https://github.com/selvinortiz/flux" target="_blank" rel="noreferrer">Flux</a> - A regular expression building library.</li></ul></li><li>Transliteration <ul><li><a href="https://github.com/jbroadway/urlify" target="_blank" rel="noreferrer">Urlify</a> - A PHP port of Django&#39;s URLify.js.</li><li><a href="https://github.com/cocur/slugify" target="_blank" rel="noreferrer">Slugify</a> - A library to convert strings to slugs.</li></ul></li><li>User-agent <ul><li><a href="https://github.com/piwik/device-detector" target="_blank" rel="noreferrer">Device Detector</a> - Another library for parsing user agent strings.</li><li><a href="https://github.com/serbanghita/Mobile-Detect" target="_blank" rel="noreferrer">Mobile-Detect</a> - A lightweight PHP class for detecting mobile devices (including tablets).</li><li><a href="https://github.com/tobie/ua-parser/tree/master/php" target="_blank" rel="noreferrer">UA Parser</a> - A library for parsing user agent strings.</li></ul></li><li>Units of measure <ul><li><a href="https://github.com/gabrielelana/byte-units" target="_blank" rel="noreferrer">ByteUnits</a> - A library to parse, format and convert byte units in binary and metric systems.</li><li><a href="https://github.com/triplepoint/php-units-of-measure" target="_blank" rel="noreferrer">PHP Units of Measure</a> - A library for converting between units of measure.</li><li><a href="https://github.com/Crisu83/php-conversion" target="_blank" rel="noreferrer">PHP Conversion</a> - Another library for converting between units of measure.</li></ul></li><li>Phone number <ul><li><a href="https://github.com/giggsey/libphonenumber-for-php" target="_blank" rel="noreferrer">LibPhoneNumber for PHP</a> - A PHP implementation of Google&#39;s phone number handling library.</li></ul></li></ul><h3 id="specific-formats-processing" tabindex="-1">Specific Formats Processing <a class="header-anchor" href="#specific-formats-processing" aria-label="Permalink to &quot;Specific Formats Processing&quot;">​</a></h3><p><em>Libraries for parsing and manipulating specific text formats.</em></p><ul><li>CSV <ul><li><a href="https://github.com/thephpleague/csv" target="_blank" rel="noreferrer">CSV</a> - A CSV data manipulation library.</li></ul></li><li>Office <ul><li><a href="https://github.com/PHPOffice/PHPWord" target="_blank" rel="noreferrer">PHPWord</a> - A library for working with Microsoft Word documents.</li><li><a href="https://github.com/PHPOffice/PHPExcel" target="_blank" rel="noreferrer">PHPExcel</a> - A library for working with Microsoft Excel documents.</li><li><a href="https://github.com/PHPOffice/PHPPowerPoint" target="_blank" rel="noreferrer">PHPPowerPoint</a> - A library for working with Microsoft PowerPoint documents.</li><li><a href="https://github.com/Wisembly/ExcelAnt" target="_blank" rel="noreferrer">ExcelAnt</a> - A library for manipulating Microsoft Excel documents.</li></ul></li><li>Markdown <ul><li><a href="https://github.com/michelf/php-markdown" target="_blank" rel="noreferrer">PHP Markdown</a> - A Markdown parser.</li><li><a href="https://github.com/thephpleague/commonmark" target="_blank" rel="noreferrer">CommonMark PHP</a> - A Markdown parser which supports the full <a href="http://spec.commonmark.org/" target="_blank" rel="noreferrer">CommonMark spec</a>.</li><li><a href="https://github.com/erusev/parsedown" target="_blank" rel="noreferrer">Parsedown</a> - Another Markdown parser.</li><li><a href="https://github.com/kzykhys/Ciconia" target="_blank" rel="noreferrer">Ciconia</a> - Another Markdown parser that supports Github flavoured Markdown.</li><li><a href="https://github.com/cebe/markdown" target="_blank" rel="noreferrer">Cebe Markdown</a> - A fast and extensible Markdown parser.</li></ul></li><li>BBCode <ul><li><a href="https://github.com/milesj/decoda" target="_blank" rel="noreferrer">Decoda</a> - A lightweight lexical string parser for BBCode styled markup.</li></ul></li><li>JSON <ul><li><a href="https://github.com/netresearch/jsonmapper" target="_blank" rel="noreferrer">JsonMapper</a> - A library that maps nested JSON structures onto PHP classes.</li></ul></li><li>vCard <ul><li><a href="https://github.com/fruux/sabre-vobject" target="_blank" rel="noreferrer">vobject</a> - The VObject library allows you to easily parse and manipulate iCalendar and vCard objects.</li></ul></li><li>File Type Detection <ul><li><a href="https://github.com/hoaproject/Mime" target="_blank" rel="noreferrer">Hoa Mime</a> - Another MIME detection library.</li><li><a href="https://github.com/dflydev/dflydev-canal" target="_blank" rel="noreferrer">Canal</a> - A library to determine internet media types.</li><li><a href="https://github.com/dflydev/dflydev-apache-mime-types" target="_blank" rel="noreferrer">Apache MIME Types</a> - A library that parses Apache MIME types.</li></ul></li><li>GeoJSON <ul><li><a href="https://github.com/jmikola/geojson" target="_blank" rel="noreferrer">GeoJSON</a> - A GeoJSON implementation.</li></ul></li></ul><h3 id="natural-language-processing" tabindex="-1">Natural Language Processing <a class="header-anchor" href="#natural-language-processing" aria-label="Permalink to &quot;Natural Language Processing&quot;">​</a></h3><p><em>Libraries for working with human languages.</em></p><ul><li><a href="https://github.com/angeloskath/php-nlp-tools" target="_blank" rel="noreferrer">PHP NlpTools</a> - Natural Language Processing Tools in PHP</li><li><a href="https://github.com/atrilla/nlptools" target="_blank" rel="noreferrer">nlpTools</a> - Natural Language Processing Toolkit for PHP</li></ul><h3 id="browser-automation-and-emulation" tabindex="-1">Browser automation and emulation <a class="header-anchor" href="#browser-automation-and-emulation" aria-label="Permalink to &quot;Browser automation and emulation&quot;">​</a></h3><ul><li><a href="https://github.com/facebook/php-webdriver" target="_blank" rel="noreferrer">php-webdriver</a> - A php client for webdriver.</li><li><a href="https://github.com/jonnnnyw/php-phantomjs" target="_blank" rel="noreferrer">PHP PhantomJS</a> - Execute PhantomJS commands through PHP</li><li><a href="https://github.com/minkphp/Mink" target="_blank" rel="noreferrer">Mink</a> - universal API for multiple browser emulators (selenium, zombie.js, goutte)</li></ul><h3 id="multiprocessing" tabindex="-1">Multiprocessing <a class="header-anchor" href="#multiprocessing" aria-label="Permalink to &quot;Multiprocessing&quot;">​</a></h3><ul><li><a href="https://github.com/kriswallsmith/spork" target="_blank" rel="noreferrer">Spork</a> - A process forking library.</li></ul><h3 id="asynchronous" tabindex="-1">Asynchronous <a class="header-anchor" href="#asynchronous" aria-label="Permalink to &quot;Asynchronous&quot;">​</a></h3><p><em>Libraries for asynchronous networking programming.</em></p><ul><li><a href="https://github.com/reactphp/react" target="_blank" rel="noreferrer">React</a> - An event driven non-blocking I/O library.</li><li><a href="https://github.com/asm89/Rx.PHP" target="_blank" rel="noreferrer">Rx.PHP</a> - A reactive extension library.</li><li><a href="https://github.com/hoaproject/Eventsource" target="_blank" rel="noreferrer">Hoa EventSource</a> - An event source library.</li><li><a href="https://github.com/igorw/evenement" target="_blank" rel="noreferrer">Evenement</a> - An event dispatcher library.</li><li><a href="https://github.com/thephpleague/event" target="_blank" rel="noreferrer">Event</a> - An event library with a focus on domain events.</li><li><a href="https://github.com/qandidate-labs/broadway" target="_blank" rel="noreferrer">Broadway</a> - An event source and CQRS library.</li></ul><h3 id="queue" tabindex="-1">Queue <a class="header-anchor" href="#queue" aria-label="Permalink to &quot;Queue&quot;">​</a></h3><ul><li><a href="https://github.com/pda/pheanstalk" target="_blank" rel="noreferrer">Pheanstalk</a> - A Beanstalkd client library.</li><li><a href="https://github.com/videlalvaro/php-amqplib" target="_blank" rel="noreferrer">PHP AMQP</a> - A pure PHP AMQP library.</li><li><a href="https://github.com/videlalvaro/Thumper" target="_blank" rel="noreferrer">Thumper</a> - A RabbitMQ pattern library.</li><li><a href="https://github.com/bernardphp/bernard" target="_blank" rel="noreferrer">Bernard</a> - A multibackend abstraction library.</li></ul><h3 id="cloud-computing" tabindex="-1">Cloud Computing <a class="header-anchor" href="#cloud-computing" aria-label="Permalink to &quot;Cloud Computing&quot;">​</a></h3><ul><li>TODO</li></ul><h3 id="email" tabindex="-1">Email <a class="header-anchor" href="#email" aria-label="Permalink to &quot;Email&quot;">​</a></h3><p><em>Libraries for parsing email.</em></p><ul><li><a href="https://github.com/willdurand/EmailReplyParser" target="_blank" rel="noreferrer">Email Reply Parser</a> - An email reply parser library.</li><li><a href="https://github.com/nojacko/email-validator" target="_blank" rel="noreferrer">Email Validator</a> - A small email address validation library.</li></ul><h3 id="url-manipulation" tabindex="-1">URL Manipulation <a class="header-anchor" href="#url-manipulation" aria-label="Permalink to &quot;URL Manipulation&quot;">​</a></h3><p><em>Libraries for parsing URLs.</em></p><ul><li><a href="https://github.com/jwage/purl" target="_blank" rel="noreferrer">Purl</a> - A URL manipulation library.</li><li><a href="https://github.com/jeremykendall/php-domain-parser" target="_blank" rel="noreferrer">PHP Domain Parser</a> - A domain suffix parser library.</li><li><a href="https://github.com/thephpleague/uri" target="_blank" rel="noreferrer">Uri</a> (The PHP League) - A simple URL manipulation library (PSR-7 compatible).</li><li><a href="https://github.com/crwlrsoft/url" target="_blank" rel="noreferrer">Url</a> (crwlr) - Swiss Army knife for urls.</li></ul><h3 id="web-content-extracting" tabindex="-1">Web Content Extracting <a class="header-anchor" href="#web-content-extracting" aria-label="Permalink to &quot;Web Content Extracting&quot;">​</a></h3><ul><li>Text and Meta Data from Web Documents <ul><li><a href="https://github.com/felixgirault/essence" target="_blank" rel="noreferrer">Essence</a> - A library for extracting web media.</li><li><a href="https://github.com/mpratt/Embera" target="_blank" rel="noreferrer">Embera</a> - An Oembed consumer library.</li><li><a href="https://github.com/oscarotero/Embed" target="_blank" rel="noreferrer">Embed</a> - An awesome library for getting useful information from a webpage.</li></ul></li><li>Video <ul><li><a href="https://github.com/jeckman/YouTube-Downloader" target="_blank" rel="noreferrer">Youtube-Downloader</a> - PHP script for downloading videos from youtube; also parsing youtube feed into RSS enclosures for podcatchers</li></ul></li></ul><h3 id="websocket" tabindex="-1">WebSocket <a class="header-anchor" href="#websocket" aria-label="Permalink to &quot;WebSocket&quot;">​</a></h3><p><em>Libraries for working with WebSocket.</em></p><ul><li><a href="https://github.com/cboden/Ratchet" target="_blank" rel="noreferrer">Ratchet</a> - A web socket library.</li><li><a href="https://github.com/hoaproject/Websocket" target="_blank" rel="noreferrer">Hoa WebSocket</a> - Another web socket library.</li><li><a href="https://github.com/Wisembly/Elephant.io" target="_blank" rel="noreferrer">Elephant.io</a> - Yet another web socket library.</li></ul><h3 id="dns-resolving" tabindex="-1">DNS Resolving <a class="header-anchor" href="#dns-resolving" aria-label="Permalink to &quot;DNS Resolving&quot;">​</a></h3><ul><li><a href="https://github.com/mikepultz/netdns2" target="_blank" rel="noreferrer">Net_DNS2</a> - Native PHP DNS Resolver and Updater</li></ul><h3 id="computer-vision" tabindex="-1">Computer Vision <a class="header-anchor" href="#computer-vision" aria-label="Permalink to &quot;Computer Vision&quot;">​</a></h3><ul><li><a href="https://github.com/mgdm/OpenCV-for-PHP" target="_blank" rel="noreferrer">OpenCV-for-PHP</a> - An OpenCV binding for PHP</li></ul><h3 id="geocoding" tabindex="-1">Geocoding <a class="header-anchor" href="#geocoding" aria-label="Permalink to &quot;Geocoding&quot;">​</a></h3><ul><li><a href="http://geocoder-php.org/" target="_blank" rel="noreferrer">GeoCoder</a> - A geocoding library.</li><li><a href="https://github.com/php-loep/Geotools" target="_blank" rel="noreferrer">GeoTools</a> - A library of geo-related tools.</li></ul><h3 id="other-php-lists" tabindex="-1">Other PHP lists <a class="header-anchor" href="#other-php-lists" aria-label="Permalink to &quot;Other PHP lists&quot;">​</a></h3><ul><li><a href="https://github.com/ziadoz/awesome-php" target="_blank" rel="noreferrer">awesome-php</a></li></ul>',48)])])}const g=r(l,[["render",o]]);export{c as __pageData,g as default};
